<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Kanban Board</title>
  <style>
    :root {
      color-scheme: light;
      --background: #f4f6fb;
      --surface: #ffffff;
      --border: #e2e7f0;
      --text: #182033;
      --muted: #687289;
      --accent: #5b67e8;
      --accent-dark: #4854d4;
      --danger: #d94a5a;
      --shadow: 0 8px 24px rgba(30, 42, 73, 0.08);
    }

    * {
      box-sizing: border-box;
    }

    body {
      min-height: 100vh;
      margin: 0;
      background:
        radial-gradient(circle at top left, rgba(91, 103, 232, 0.1), transparent 34rem),
        var(--background);
      color: var(--text);
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    button,
    input {
      font: inherit;
    }

    .app {
      width: min(1180px, calc(100% - 32px));
      margin: 0 auto;
      padding: 42px 0;
    }

    .app-header {
      display: flex;
      align-items: end;
      justify-content: space-between;
      gap: 24px;
      margin-bottom: 28px;
    }

    .title-block h1 {
      margin: 0;
      font-size: clamp(1.8rem, 4vw, 2.7rem);
      letter-spacing: -0.04em;
    }

    .title-block p {
      margin: 8px 0 0;
      color: var(--muted);
    }

    .new-card-form {
      display: flex;
      width: min(100%, 460px);
      padding: 6px;
      border: 1px solid var(--border);
      border-radius: 14px;
      background: var(--surface);
      box-shadow: var(--shadow);
    }

    #new-card {
      min-width: 0;
      flex: 1;
      padding: 10px 12px;
      border: 0;
      outline: 0;
      color: var(--text);
      background: transparent;
    }

    #new-card::placeholder {
      color: #929aab;
    }

    #add-card {
      border: 0;
      border-radius: 10px;
      padding: 10px 18px;
      background: var(--accent);
      color: #fff;
      font-weight: 700;
      cursor: pointer;
      transition: background 160ms ease, transform 160ms ease;
    }

    #add-card:hover {
      background: var(--accent-dark);
    }

    #add-card:active {
      transform: translateY(1px);
    }

    .board {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 20px;
      align-items: start;
    }

    .column {
      min-height: 490px;
      padding: 18px;
      border: 1px solid var(--border);
      border-radius: 18px;
      background: rgba(255, 255, 255, 0.68);
      transition: border-color 160ms ease, background 160ms ease, transform 160ms ease;
    }

    .column.drag-over {
      border-color: var(--accent);
      background: rgba(91, 103, 232, 0.07);
      transform: translateY(-2px);
    }

    .column-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: 16px;
    }

    .column-header h2 {
      margin: 0;
      font-size: 1rem;
      letter-spacing: -0.01em;
    }

    .count {
      display: inline-grid;
      min-width: 28px;
      height: 28px;
      place-items: center;
      padding: 0 8px;
      border-radius: 999px;
      background: #e9ecf5;
      color: #5c6578;
      font-size: 0.82rem;
      font-weight: 800;
    }

    #col-todo .count {
      background: #edeaff;
      color: #6153c8;
    }

    #col-doing .count {
      background: #fff0cf;
      color: #9c6810;
    }

    #col-done .count {
      background: #dff5e9;
      color: #268553;
    }

    .cards {
      display: flex;
      min-height: 410px;
      flex-direction: column;
      gap: 12px;
    }

    .cards:empty::after {
      content: "Drop cards here";
      display: grid;
      min-height: 88px;
      place-items: center;
      border: 1px dashed #ccd2df;
      border-radius: 13px;
      color: #969eae;
      font-size: 0.87rem;
    }

    .card {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      padding: 15px 14px 15px 16px;
      border: 1px solid var(--border);
      border-radius: 13px;
      background: var(--surface);
      box-shadow: 0 5px 16px rgba(32, 43, 70, 0.07);
      cursor: grab;
      overflow-wrap: anywhere;
      transition: box-shadow 160ms ease, transform 160ms ease, opacity 160ms ease;
    }

    .card:hover {
      transform: translateY(-1px);
      box-shadow: 0 9px 21px rgba(32, 43, 70, 0.11);
    }

    .card.dragging {
      opacity: 0.45;
      cursor: grabbing;
    }

    .card-title {
      min-width: 0;
      padding-top: 3px;
      line-height: 1.4;
    }

    .card-del {
      width: 28px;
      height: 28px;
      flex: 0 0 auto;
      border: 0;
      border-radius: 8px;
      background: transparent;
      color: #8b93a5;
      font-size: 1.15rem;
      line-height: 1;
      cursor: pointer;
      transition: color 150ms ease, background 150ms ease;
    }

    .card-del:hover {
      background: #fdebed;
      color: var(--danger);
    }

    @media (max-width: 800px) {
      .app-header {
        align-items: stretch;
        flex-direction: column;
      }

      .new-card-form {
        width: 100%;
      }

      .board {
        grid-template-columns: 1fr;
      }

      .column {
        min-height: 260px;
      }

      .cards {
        min-height: 180px;
      }
    }
  </style>
</head>
<body>
  <main class="app">
    <header class="app-header">
      <div class="title-block">
        <h1>Kanban Board</h1>
        <p>Organize tasks and drag them through your workflow.</p>
      </div>

      <form class="new-card-form" id="new-card-form">
        <input
          id="new-card"
          type="text"
          autocomplete="off"
          placeholder="Add a new task…"
          aria-label="New card title"
        >
        <button id="add-card" type="submit">Add card</button>
      </form>
    </header>

    <section class="board" aria-label="Kanban board">
      <section class="column" id="col-todo">
        <header class="column-header">
          <h2>To Do</h2>
          <span class="count" aria-label="0 cards">0</span>
        </header>
        <div class="cards" aria-label="To Do cards"></div>
      </section>

      <section class="column" id="col-doing">
        <header class="column-header">
          <h2>Doing</h2>
          <span class="count" aria-label="0 cards">0</span>
        </header>
        <div class="cards" aria-label="Doing cards"></div>
      </section>

      <section class="column" id="col-done">
        <header class="column-header">
          <h2>Done</h2>
          <span class="count" aria-label="0 cards">0</span>
        </header>
        <div class="cards" aria-label="Done cards"></div>
      </section>
    </section>
  </main>

  <script>
    (() => {
      "use strict";

      const STORAGE_KEY = "kanban-board-state";
      const columnIds = ["col-todo", "col-doing", "col-done"];
      const columns = columnIds.map(id => document.getElementById(id));
      const form = document.getElementById("new-card-form");
      const input = document.getElementById("new-card");
      let draggedCardId = null;

      function createId() {
        if (window.crypto && typeof window.crypto.randomUUID === "function") {
          return "card-" + window.crypto.randomUUID();
        }

        return "card-" + Date.now() + "-" + Math.random().toString(36).slice(2);
      }

      function updateCounts() {
        columns.forEach(column => {
          const count = column.querySelectorAll(".card").length;
          const countElement = column.querySelector(".count");
          countElement.textContent = String(count);
          countElement.setAttribute("aria-label", count + (count === 1 ? " card" : " cards"));
        });
      }

      function getBoardState() {
        const state = [];

        columns.forEach(column => {
          column.querySelectorAll(".card").forEach(card => {
            state.push({
              id: card.id,
              title: card.querySelector(".card-title").textContent,
              column: column.id
            });
          });
        });

        return state;
      }

      function saveBoard() {
        try {
          localStorage.setItem(STORAGE_KEY, JSON.stringify(getBoardState()));
        } catch (error) {
          console.warn("Unable to save the board.", error);
        }
      }

      function makeCard(title, id = createId()) {
        const card = document.createElement("article");
        card.className = "card";
        card.id = id;
        card.draggable = true;

        const titleElement = document.createElement("span");
        titleElement.className = "card-title";
        titleElement.textContent = title;

        const deleteButton = document.createElement("button");
        deleteButton.className = "card-del";
        deleteButton.type = "button";
        deleteButton.textContent = "×";
        deleteButton.setAttribute("aria-label", "Delete " + title);

        deleteButton.addEventListener("click", () => {
          card.remove();
          updateCounts();
          saveBoard();
        });

        card.addEventListener("dragstart", event => {
          draggedCardId = card.id;
          card.classList.add("dragging");

          if (event.dataTransfer) {
            event.dataTransfer.effectAllowed = "move";
            event.dataTransfer.setData("text/plain", card.id);
          }
        });

        card.addEventListener("dragend", () => {
          draggedCardId = null;
          card.classList.remove("dragging");
          columns.forEach(column => column.classList.remove("drag-over"));
        });

        card.append(titleElement, deleteButton);
        return card;
      }

      function addCard(title, columnId = "col-todo", id) {
        const cleanedTitle = String(title).trim();
        if (!cleanedTitle) return null;

        const column = document.getElementById(columnId) || document.getElementById("col-todo");
        const card = makeCard(cleanedTitle, id);
        column.querySelector(".cards").appendChild(card);
        updateCounts();
        return card;
      }

      function restoreBoard() {
        let state = [];

        try {
          const savedState = JSON.parse(localStorage.getItem(STORAGE_KEY) || "[]");
          if (Array.isArray(savedState)) state = savedState;
        } catch (error) {
          state = [];
        }

        state.forEach(item => {
          if (
            item &&
            typeof item.title === "string" &&
            typeof item.id === "string" &&
            columnIds.includes(item.column)
          ) {
            addCard(item.title, item.column, item.id);
          }
        });

        updateCounts();
      }

      form.addEventListener("submit", event => {
        event.preventDefault();

        const title = input.value.trim();
        if (!title) return;

        addCard(title);
        input.value = "";
        saveBoard();
        input.focus();
      });

      columns.forEach(column => {
        column.addEventListener("dragover", event => {
          event.preventDefault();
          column.classList.add("drag-over");

          if (event.dataTransfer) {
            event.dataTransfer.dropEffect = "move";
          }
        });

        column.addEventListener("dragleave", event => {
          if (!column.contains(event.relatedTarget)) {
            column.classList.remove("drag-over");
          }
        });

        column.addEventListener("drop", event => {
          event.preventDefault();

          const transferredId = event.dataTransfer
            ? event.dataTransfer.getData("text/plain")
            : "";
          const cardId = transferredId || draggedCardId;
          const card = cardId ? document.getElementById(cardId) : null;

          if (card && card.classList.contains("card")) {
            column.querySelector(".cards").appendChild(card);
            updateCounts();
            saveBoard();
          }

          column.classList.remove("drag-over");
        });
      });

      restoreBoard();
    })();
  </script>
</body>
</html>
